# Problem: Implement a simplified version of Python's logging system
# to understand the Logger → Handler → Formatter pipeline.
#
# Approach: Build five classes that mirror Python's logging architecture:
#   LogLevel (constants + name lookup), LogRecord (data carrier),
#   SimpleHandler (filtering + storage), SimpleFormatter (string formatting),
#   SimpleLogger (facade with convenience methods).
#   The pipeline: logger checks its level → creates LogRecord → handlers
#   each check their own level → optional formatter → store output string.
#
# Time complexity: O(H) per log call where H = number of handlers
# Space complexity: O(N) where N = number of emitted records
#
# Key steps:
#   1. LogLevel.name() reverse-maps int → string via class attribute inspection
#   2. LogRecord bundles level, message, logger_name, and derived level_name
#   3. SimpleHandler.emit() filters by level, applies formatter if present
#   4. SimpleFormatter.format() uses str.format_map() with record fields
#   5. SimpleLogger.log() gates on logger level, then delegates to all handlers

class LogLevel:
    DEBUG = 10
    INFO = 20
    WARNING = 30
    ERROR = 40
    CRITICAL = 50

    # Build reverse lookup once: {10: 'DEBUG', 20: 'INFO', ...}
    _names = {}

    @classmethod
    def name(cls, level: int) -> str:
        # Lazily populate the reverse map from class constants
        if not cls._names:
            cls._names = {
                v: k for k, v in vars(cls).items()
                if isinstance(v, int) and not k.startswith('_')
            }
        return cls._names.get(level, f'LEVEL_{level}')


class LogRecord:
    def __init__(self, level: int, message: str, logger_name: str):
        self.level = level
        self.message = message
        self.logger_name = logger_name
        self.level_name = LogLevel.name(level)


class SimpleHandler:
    def __init__(self, level: int = 0):
        self.level = level
        self.formatter = None
        self.records = []

    def emit(self, record):
        if record.level >= self.level:
            if self.formatter:
                self.records.append(self.formatter.format(record))
            else:
                self.records.append(record.message)


class SimpleFormatter:
    def __init__(self, fmt: str = '{level_name}:{logger_name}:{message}'):
        self.fmt = fmt

    def format(self, record) -> str:
        # Use format_map with record's __dict__ for named placeholder substitution
        return self.fmt.format_map(vars(record))


class SimpleLogger:
    def __init__(self, name: str, level: int = 0):
        self.name = name
        self.level = level
        self.handlers = []

    def add_handler(self, handler):
        self.handlers.append(handler)

    def log(self, level: int, message: str):
        if level >= self.level:
            record = LogRecord(level, message, self.name)
            for handler in self.handlers:
                handler.emit(record)  # Each handler does its own level check

    def debug(self, message: str):
        self.log(LogLevel.DEBUG, message)

    def info(self, message: str):
        self.log(LogLevel.INFO, message)

    def warning(self, message: str):
        self.log(LogLevel.WARNING, message)

    def error(self, message: str):
        self.log(LogLevel.ERROR, message)

    def critical(self, message: str):
        self.log(LogLevel.CRITICAL, message)
